from autogen import ConversableAgent

# Minimal LLM-backed agent
agent = ConversableAgent(
    name="analyst",
    system_message="You are a data analyst. Answer questions concisely with numbers.",
    llm_config={
        "config_list": [{"model": "gpt-4o-mini", "api_key": "sk-..."}],
    },
    human_input_mode="NEVER",   # never ask a human for input
)
